(function(){
  // Wire tree and sign tile images as building sprites
  function syncProp(key, tileKey){
    const check = setInterval(()=>{
      if(typeof TILE_IMAGES!=='undefined' && TILE_IMAGES[tileKey] &&
         typeof BUILDING_IMAGES!=='undefined'){
        BUILDING_IMAGES[key] = TILE_IMAGES[tileKey];
        clearInterval(check);
      }
    }, 50);
  }
  syncProp('tree_sprite', 'tree');
  syncProp('sign_post',   'sign');
})();

